import{_ as a,o,c as i,ag as t}from"./chunks/framework.D4O_uTxf.js";const h=JSON.parse('{"title":"Venture Track B Treasury + Compliance","description":"","frontmatter":{},"headers":[],"relativePath":"venture/track-b.md","filePath":"venture/track-b.md","lastUpdated":1771844172000}'),r={name:"venture/track-b.md"};function n(l,e,c,d,s,p){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="venture-track-b-treasury-compliance" tabindex="-1">Venture Track B Treasury + Compliance <a class="header-anchor" href="#venture-track-b-treasury-compliance" aria-label="Permalink to &quot;Venture Track B Treasury + Compliance&quot;">​</a></h1><p>Source mirror: <code>./venture/TRACK_B_TREASURY_COMPLIANCE_SPEC.md</code></p><h1 id="venture-track-b-treasury-ledger-and-compliance-closure" tabindex="-1">Venture Track B Treasury, Ledger, and Compliance Closure <a class="header-anchor" href="#venture-track-b-treasury-ledger-and-compliance-closure" aria-label="Permalink to &quot;Venture Track B Treasury, Ledger, and Compliance Closure&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Closes Track B gaps for money policy, ledger/reconciliation model, and compliance/privacy controls.</p><h2 id="money-authorization-model" tabindex="-1">Money Authorization Model <a class="header-anchor" href="#money-authorization-model" aria-label="Permalink to &quot;Money Authorization Model&quot;">​</a></h2><ol><li>Default-deny for all spend attempts.</li><li>Spend envelope requires <code>money_intent</code> with TTL, vendor/MCC scope, budget class, workflow binding.</li><li>Authorization decision requires policy bundle evaluation and reason code.</li><li>Revocation is immediate and emits freeze events for downstream workflows.</li></ol><h2 id="ledger-and-reconciliation" tabindex="-1">Ledger and Reconciliation <a class="header-anchor" href="#ledger-and-reconciliation" aria-label="Permalink to &quot;Ledger and Reconciliation&quot;">​</a></h2><ol><li>Every approved spend creates immutable ledger entries.</li><li>External processor references are linked to internal ledger IDs.</li><li>Daily reconciliation compares internal ledger, processor exports, and bank statements.</li><li>Drift above threshold opens compliance case automatically.</li></ol><h2 id="compliance-and-privacy-controls" tabindex="-1">Compliance and Privacy Controls <a class="header-anchor" href="#compliance-and-privacy-controls" aria-label="Permalink to &quot;Compliance and Privacy Controls&quot;">​</a></h2><ol><li>Jurisdiction gates on outreach, payment, and data export actions.</li><li>Machine-readable policy packs for tax, retention, suppression, and do-not-sell/share.</li><li>DSAR/deletion workflows tracked with due dates and status state machine.</li><li>Audit trail is append-only and includes policy version on every decision.</li></ol><h2 id="data-db-additions" tabindex="-1">Data/DB Additions <a class="header-anchor" href="#data-db-additions" aria-label="Permalink to &quot;Data/DB Additions&quot;">​</a></h2><ol><li><code>money_limits(id, scope_type, scope_id, cap_amount, window, status, created_at)</code></li><li><code>reconciliation_runs(id, period_start, period_end, drift_amount, status, created_at)</code></li><li><code>policy_attestations(id, policy_bundle_id, attestor, result, created_at)</code></li><li><code>privacy_classifications(id, entity_ref, class, sharing_default, created_at)</code></li></ol><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to &quot;Events&quot;">​</a></h2><ol><li><code>money.limit.updated.v1</code></li><li><code>money.authorization.revoked.v1</code></li><li><code>ledger.reconciliation.completed.v1</code></li><li><code>compliance.policy.attested.v1</code></li><li><code>privacy.classification.updated.v1</code></li></ol><h2 id="acceptance-checks" tabindex="-1">Acceptance Checks <a class="header-anchor" href="#acceptance-checks" aria-label="Permalink to &quot;Acceptance Checks&quot;">​</a></h2><ol><li>Unauthorized spend attempts are denied and logged with reason code.</li><li>Reconciliation drift is detected deterministically and creates case records.</li><li>Policy pack updates propagate to authorization/compliance decisions without silent fallback.</li></ol>',17)])])}const m=a(r,[["render",n]]);export{h as __pageData,m as default};
